CREATE TABLE IF NOT EXISTS `auth_audit_log` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `event_type` varchar(32) NOT NULL DEFAULT 'login',
  `action` varchar(64) DEFAULT NULL,
  `provider` varchar(64) DEFAULT NULL,
  `provider_user_id` varchar(255) DEFAULT NULL,
  `provider_email` varchar(255) DEFAULT NULL,
  `email_attempted` varchar(255) DEFAULT NULL,
  `username_attempted` varchar(255) DEFAULT NULL,
  `login_method` varchar(64) DEFAULT NULL,
  `success` tinyint(1) DEFAULT NULL,
  `failure_reason` varchar(255) DEFAULT NULL,
  `status` varchar(64) DEFAULT NULL,
  `error_message` text DEFAULT NULL,
  `ip_address` varchar(64) DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `device_name` varchar(191) DEFAULT NULL,
  `browser` varchar(191) DEFAULT NULL,
  `os` varchar(191) DEFAULT NULL,
  `details` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`details`)),
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_auth_audit_user_id` (`user_id`),
  KEY `idx_auth_audit_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=242 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

